VALUES
  ('social-worker-moex-08110', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '對於「任務中心」社會工作理論的敘述，下列何者為非？', '["任務中心實務建立在案主同意的基礎上或案主承認依法必須採取行動", "任務中心實務基於任務，任務是改變過程的核心", "應與案主建立長期的任務關係", "任務中心實務需要案主以自己的力量，促成改變"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08111', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '對於「充權（empowerment）」社會工作理論的敘述，下列何者為非？', '["社會工作者承擔專家權威者的角色", "透過工作人員對服務使用者的支持過程，來辨識可以滿足需求的各種可能性", "將焦點放在服務使用者對自身社會環境的理解", "減低服務使用者的孤立感，促進服務使用者的彼此連結"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08112', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '把身心障礙者視為「因身體或社會障礙的緣故，喪失與他人平等參與社區正常生活機會或機會受到限制」 而採取解除社會障礙的相關服務。這是何種理論觀點？', '["醫學模型", "心理模型", "社會模型", "衝突模型"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08113', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關「基變」社會工作取向的敘述，下列何者為非？', '["將社會問題個人化，並強化案主遵循資本主義的社會秩序，干預的策略採取個別化", "主張以結構分析來解釋案主問題形成的原因，用干預的目標來協助案主發展自我控制的力量", "基變取向的個案評量是從環境資源、物資供應的不適當作為分析焦點", "強調社會結構非個人能力得以解決，而必須以集體政治行動介入以達成目的"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08114', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關「危機理論」的敘述，下列何者為非？', '["危機是人對情境或生活壓力無法產生正常的因應機制所致", "危機處遇的服務是無法協助案主恢復到危機發生前的適應力", "克服危機被視為人的成長過程之一部分，也是發展健康自尊所必要的", "有效的危機處遇是迅速提供協助，但協助的是採取短期處遇無法協助案主恢復到危機發生前的適應力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08115', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Reamer（1998）論述社會工作價值與倫理在不同的歷史階段中有不同的認知與關注焦點，下列敘述何者為 非？', '["第一階段是在十九世紀末期，社會工作專業發展初期，大家關切的是案主的思想是否合乎道德的標準", "第二階段是在二十世紀初期，隨著睦鄰運動興起，轉而關心社會改革議題", "第三階段是在1940年代末期與1950年代初期，應用性的專業倫理開始興起", "第四階段是在1960至1970年代，關注焦點轉向重視社會平等、福利權利、歧視與壓迫等問題"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08116', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在規範倫理學的理論中，下列那一種理論主張：「某些行為無論其結果如何，都有其本有的對或錯，好或 壞之分；有關規定、權利、原則或法律等，皆被視為神聖，需要遵守，不可違背的」？', '["唯心論", "唯物論", "義務論（de-ontological theories）", "目的論（teleological theories）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08117', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在倫理學的理論中主張：行為的正確性是決定於針對該個案或該特定行為所帶來的結果，不需要再探討行 為產生的隱含意義。例如，社會工作者對於特定的兒虐事件，不依法舉發可帶來更大的益處，則認為該不 舉發行為是合理的。請問這是那一個學派的觀點？', '["規則的效益主義（rule utilitarianism）", "行為的效益主義（act utilitarianism）", "利益累積式的效益主義（good-aggregative utilitarianism）", "集中累積式的效益主義（locus-aggregative utilitarianism）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08118', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Rawls之著作「正義論」主張：每一個人是在一種平等的原初立場去形成道德，每個人並不知道其自身的特 質與身分地位，在此「無知之幕」（veil of ignorance）的狀況下，個人發展出的道德觀念不會圖利自己。此 概念對於排列價值與倫理義務的優先順序有極重要的意義，Rawls稱之為何種原則？', '["自由原則", "博愛原則", "平等原則", "差異原則"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08119', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Lewis（1972）指出社會工作價值與實務工作的執行有直接的關連，如果以「分配正義」為核心價值，會衍 生出來那種實務原則與之對應？', '["在服務關係中，不可過分要求案主", "服務的提供應包含多種選擇", "符合資格的案主應被告知其可以參與方案的內容", "專業與其相關機構必須對於實務工作中不公平的歧視行為予以對抗"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
